import org.w3c.dom.Node;
import org.xml.sax.EntityResolver;
import org.xml.sax.ErrorHandler;
import org.xml.sax.InputSource;
import org.xml.sax.SAXException;
import org.xml.sax.SAXNotRecognizedException;
import org.xml.sax.SAXNotSupportedException;
import org.xml.sax.SAXParseException;
import org.xml.sax.XMLReader;

import javax.xml.XMLConstants;
import javax.xml.parsers.ParserConfigurationException;
import javax.xml.parsers.SAXParser;
import javax.xml.parsers.SAXParserFactory;
import javax.xml.transform.Transformer;
import javax.xml.transform.TransformerFactory;
import javax.xml.transform.TransformerException;
import javax.xml.transform.dom.DOMResult;
import javax.xml.transform.sax.SAXSource;
import java.io.BufferedInputStream;
import java.io.File;
import java.io.FileInputStream;
import java.io.InputStream;
import java.io.StringReader;
import java.io.IOException;

/**
 * 配置服务类
 * 用于加载XML格式的配置文件
 */
public class ConfigService {

    /**
     * 根据用户指定的配置文件路径加载XML配置
     *
     * @param configPath 配置文件路径
     * @return 解析后的XML文档对象
     * @throws Exception 当文件不存在或解析失败时抛出异常
     */
    public Document loadConfig(String configPath) throws Exception {
        if (configPath == null || configPath.trim().isEmpty()) {
            throw new IllegalArgumentException("配置文件路径不能为空");
        }

        File configFile = new File(configPath);
        if (!configFile.exists() || !configFile.isFile()) {
            throw new IOException("配置文件不存在或不是一个文件: " + configPath);
        }
        if (!configFile.canRead()) {
            throw new IOException("配置文件不可读: " + configPath);
        }

        // 安全配置并创建SAX解析器
        SAXParserFactory factory = SAXParserFactory.newInstance();
        configureSaxFactorySecurely(factory);

        // 安全配置Transformer
        TransformerFactory transformerFactory = TransformerFactory.newInstance();
        configureTransformerFactorySecurely(transformerFactory);

        try (InputStream in = new BufferedInputStream(new FileInputStream(configFile))) {
            SAXParser parser = factory.newSAXParser();
            XMLReader reader = parser.getXMLReader();

            // 双重保险：在XMLReader上再次设置安全特性
            configureXmlReaderSecurely(reader);

            // 禁止外部实体解析
            reader.setEntityResolver(noExternalEntityResolver());

            // 提升错误可读性
            reader.setErrorHandler(strictErrorHandler());

            // 使用Transformer将SAX事件流转换为DOM树
            Transformer transformer = transformerFactory.newTransformer();

            InputSource inputSource = new InputSource(in);
            // 设置systemId有助于解析相对路径，但我们已禁用外部访问，仍设置以保留上下文
            inputSource.setSystemId(configFile.toURI().toString());

            SAXSource source = new SAXSource(reader, inputSource);
            DOMResult result = new DOMResult();

            transformer.transform(source, result);

            Node node = result.getNode();
            Document doc = (node instanceof Document) ? (Document) node
                    : (node != null ? node.getOwnerDocument() : null);

            if (doc == null) {
                throw new TransformerException("XML解析结果为空");
            }
            return doc;
        } catch (ParserConfigurationException | SAXException | TransformerException e) {
            throw new Exception("XML解析失败: " + e.getMessage(), e);
        }
    }

    private static void configureSaxFactorySecurely(SAXParserFactory factory)
            throws ParserConfigurationException, SAXNotRecognizedException, SAXNotSupportedException {
        factory.setNamespaceAware(true);
        factory.setValidating(false);

        // 某些JDK实现可能不支持XInclude，捕获并忽略
        try {
            factory.setXIncludeAware(false);
        } catch (UnsupportedOperationException ignored) {
            // ignore
        }

        // 启用安全处理
        factory.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);

        // 禁止DOCTYPE与外部实体
        factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
        factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
        factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
        factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);

        // 可选: 防止解析器解析DTD时解析URI
        try {
            factory.setFeature("http://xml.org/sax/features/resolve-dtd-uris", false);
        } catch (SAXNotRecognizedException | SAXNotSupportedException ignored) {
            // 部分实现不支持
        }
    }

    private static void configureXmlReaderSecurely(XMLReader reader)
            throws SAXNotRecognizedException, SAXNotSupportedException {
        // 再次设置，确保安全特性生效
        try {
            reader.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);
        } catch (SAXNotRecognizedException | SAXNotSupportedException ignored) {
            // 某些实现不支持在XMLReader上设置该特性
        }
        reader.setFeature("http://xml.org/sax/features/namespaces", true);

        // 禁用外部实体和外部DTD
        safeSet(reader, "http://apache.org/xml/features/disallow-doctype-decl", true);
        safeSet(reader, "http://xml.org/sax/features/external-general-entities", false);
        safeSet(reader, "http://xml.org/sax/features/external-parameter-entities", false);
        safeSet(reader, "http://apache.org/xml/features/nonvalidating/load-external-dtd", false);

        // 可选
        safeSet(reader, "http://xml.org/sax/features/resolve-dtd-uris", false);
    }

    private static void safeSet(XMLReader reader, String feature, boolean value) {
        try {
            reader.setFeature(feature, value);
        } catch (SAXNotRecognizedException | SAXNotSupportedException ignored) {
            // 忽略不支持的特性
        }
    }

    private static void configureTransformerFactorySecurely(TransformerFactory tf) {
        try {
            tf.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);
        } catch (Exception ignored) {
            // 某些实现不支持，忽略
        }
        // 禁止Transformer访问外部资源
        try {
            tf.setAttribute(XMLConstants.ACCESS_EXTERNAL_DTD, "");
        } catch (IllegalArgumentException ignored) {
            // 实现不支持该属性
        }
        try {
            tf.setAttribute(XMLConstants.ACCESS_EXTERNAL_STYLESHEET, "");
        } catch (IllegalArgumentException ignored) {
            // 实现不支持该属性
        }
    }

    private static EntityResolver noExternalEntityResolver() {
        return (publicId, systemId) -> new InputSource(new StringReader(""));
    }

    private static ErrorHandler strictErrorHandler() {
        return new ErrorHandler() {
            @Override
            public void warning(SAXParseException exception) throws SAXException {
                // 将警告视为错误，便于严格校验
                throw exception;
            }

            @Override
            public void error(SAXParseException exception) throws SAXException {
                throw exception;
            }

            @Override
            public void fatalError(SAXParseException exception) throws SAXException {
                throw exception;
            }
        };
    }
}

